const { test } = require('node:test');
const assert = require('node:assert');
const { spawn } = require('node:child_process');
const { setTimeout: delay } = require('node:timers/promises');

async function waitForHealth(url, retries = 50, intervalMs = 100) {
  for (let i = 0; i < retries; i++) {
    try {
      const res = await fetch(url);
      if (res.ok) {
        return res;
      }
    } catch (_) {}
    await delay(intervalMs);
  }
  throw new Error('Server did not become healthy in time');
}

test('server starts on 4566, /health ok, and serves index.html', async () => {
  const child = spawn(process.execPath, ['src/server.js'], { stdio: ['ignore', 'pipe', 'pipe'] });

  try {
    // Wait for health endpoint
    const healthRes = await waitForHealth('http://localhost:4566/health');
    const healthJson = await healthRes.json();
    assert.strictEqual(healthJson.status, 'ok');

    // Fetch index.html
    const indexRes = await fetch('http://localhost:4566/');
    assert.strictEqual(indexRes.status, 200);
    const html = await indexRes.text();
    assert.match(html, /Flash Cards/);
  } finally {
    child.kill('SIGTERM');
    await delay(100);
  }
});
